import { useState, useEffect } from "react";
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from "recharts";

const ALLANA_PHOTO = "data:image/jpeg;base64,";

const GCAL_MCP_URL = "https://gcal.mcp.claude.com/mcp";

const COLORS = {
  prospeccao: "#F59E0B",
  reuniao: "#3B82F6",
  proposta: "#10B981",
  followup: "#8B5CF6",
};

const ACTIVITY_LABELS = {
  prospeccao: "Prospecção",
  reuniao: "Reunião",
  proposta: "Envio de Proposta",
  followup: "Follow-up",
};

const ACTIVITY_KEYWORDS = {
  prospeccao: ["prospect", "prospec", "lead", "cold call", "abordagem", "contato inicial"],
  reuniao: ["reunião", "reuniao", "meeting", "call", "conversa", "apresentação comercial"],
  proposta: ["proposta", "proposal", "cotação", "cotacao", "orçamento", "orcamento"],
  followup: ["follow", "retorno", "acompanhamento", "follow-up", "followup"],
};

const detectActivityType = (eventTitle) => {
  const title = eventTitle.toLowerCase();
  for (const [type, keywords] of Object.entries(ACTIVITY_KEYWORDS)) {
    if (keywords.some((k) => title.includes(k))) return type;
  }
  return null;
};

const formatDate = (d) =>
  new Date(d).toLocaleDateString("pt-BR", { day: "2-digit", month: "2-digit", year: "numeric" });

const formatBRL = (v) =>
  new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL", maximumFractionDigits: 0 }).format(v);

const getQuinzenaRange = (offset = 0) => {
  const now = new Date();
  const day = now.getDate();
  let start, end;
  const month = now.getMonth() - offset;
  const year = now.getFullYear();
  if (day <= 15) {
    start = new Date(year, month, 1);
    end = new Date(year, month, 15, 23, 59, 59);
  } else {
    start = new Date(year, month, 16);
    end = new Date(year, month + 1, 0, 23, 59, 59);
  }
  return { start, end };
};

